#include "markforge/markforge.h"
#include "markforge/test.h"
void test_containers_module(void){ mf_vector_t v; mf_queue_t q; mf_hash_map_t m; mf_string_builder_t sb; int a=1,b=2; MF_TEST_ASSERT_EQ_INT(mf_vector_init(&v),MF_OK); MF_TEST_ASSERT_EQ_INT(mf_vector_push(&v,&a),MF_OK); MF_TEST_ASSERT(mf_vector_get(&v,0)==&a); mf_vector_destroy(&v); MF_TEST_ASSERT_EQ_INT(mf_queue_init(&q),MF_OK); mf_queue_push(&q,&a); mf_queue_push(&q,&b); MF_TEST_ASSERT(mf_queue_pop(&q)==&a); mf_queue_destroy(&q); MF_TEST_ASSERT_EQ_INT(mf_hash_map_init(&m),MF_OK); mf_hash_map_put(&m,"k",&b); MF_TEST_ASSERT(mf_hash_map_get(&m,"k")==&b); mf_hash_map_destroy(&m); mf_sb_init(&sb); mf_sb_append(&sb,"Mark"); mf_sb_append(&sb,"Forge"); MF_TEST_ASSERT_STR(mf_sb_cstr(&sb),"MarkForge"); mf_sb_destroy(&sb); }
